// src/App.js - WITH GLOBAL LOADER AND TOKEN EXPIRATION
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import LoginPage from './components/Auth/LoginPage';
import Dashboard from './components/Dashboard/Dashboard';
import GlobalLoader from './components/Common/GlobalLoader';
import { 
  api, 
  storeLoginTime, 
  checkTokenOnStartup, 
  isTokenExpired,
  getTokenRemainingTime,
  performLogout 
} from './utils/api';
import './styles/App.css';

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [userName, setUserName] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('Loading...');

  // Check token expiration on mount
  useEffect(() => {
    checkTokenOnStartup();

    const token = localStorage.getItem('dashboard_token');
    const user = localStorage.getItem('dashboard_user');
    if (token && user) {
      setIsAuthenticated(true);
      setUserName(JSON.parse(user).name);

      // Setup auto-logout timer
      setupAutoLogoutTimer();
    }
  }, []);

  // Setup timer to auto-logout when token expires
  const setupAutoLogoutTimer = () => {
    const remainingTime = getTokenRemainingTime();

    if (remainingTime > 0) {
      console.log(`⏰ Auto-logout scheduled in ${remainingTime}ms (7 days)`);

      // Set timeout for exact expiration time
      const timer = setTimeout(() => {
        console.log('🔒 Session expired after 7 days, logging out...');
        alert('Your session has expired after 7 days. Please login again.');
        performLogout();
      }, remainingTime);

      // Cleanup timer on unmount
      return () => clearTimeout(timer);
    } else {
      // Already expired
      performLogout();
    }
  };

  // Global API interceptor for loading state
  useEffect(() => {
    // Request interceptor - show loader
    const requestInterceptor = api.interceptors.request.use(
      (config) => {
        // Don't show loader for quick requests or polling
        if (!config.hideLoader) {
          setIsLoading(true);
          setLoadingMessage('Loading data...');
        }
        return config;
      },
      (error) => {
        setIsLoading(false);
        return Promise.reject(error);
      }
    );

    // Response interceptor - hide loader
    const responseInterceptor = api.interceptors.response.use(
      (response) => {
        setIsLoading(false);
        return response;
      },
      (error) => {
        setIsLoading(false);

        // Show error message if not 401 (handled by api.js)
        if (error.response?.status !== 401) {
          console.error('API Error:', error);
        }

        return Promise.reject(error);
      }
    );

    // Cleanup interceptors
    return () => {
      api.interceptors.request.eject(requestInterceptor);
      api.interceptors.response.eject(responseInterceptor);
    };
  }, []);

  const handleLogin = async (mobile, password) => {
    setIsLoading(true);
    setLoadingMessage('Logging in...');

    try {
      const response = await axios.post(
        'https://makhanchor-backend.onrender.com/api/auth/login',
        { mobile, password }
      );

      if (response.data.success) {
        // Store token and user data
        localStorage.setItem('dashboard_token', response.data.token);
        localStorage.setItem('dashboard_user', JSON.stringify(response.data.user));

        // Store login timestamp for 7-day expiration
        storeLoginTime();

        setUserName(response.data.user.name);
        setIsAuthenticated(true);

        // Setup auto-logout timer
        setupAutoLogoutTimer();

        setIsLoading(false);
        return { success: true };
      }
    } catch (error) {
      setIsLoading(false);
      console.log("error:");

      return {
        success: false,
        message: error.response?.data?.message || 'Invalid credentials',
      };
    }
  };

  const handleLogout = () => {
    setIsLoading(true);
    setLoadingMessage('Logging out...');

    setTimeout(() => {
      performLogout();
    }, 500);
  };

  // Show global loader when loading
  if (isLoading) {
    return <GlobalLoader message={loadingMessage} />;
  }

  if (!isAuthenticated) {
    return <LoginPage onLogin={handleLogin} />;
  }

  return <Dashboard userName={userName} onLogout={handleLogout} />;
};

export default App;
